  top: -10%;
  left: 10%;
}

.blob-2 {
  width: 450px;
  height: 450px;
  background: #e0e7ff;
  bottom: 10%;
  right: -5%;
  animation-delay: 2s;
}

.blob-3 {
  width: 300px;
  height: 300px;
  background: #fae8ff;
  top: 40%;
  left: 60%;
  animation-delay: 4s;
}

@keyframes float-blobs {
  0% { transform: translateY(0) scale(1); }
  100% { transform: translateY(30px) scale(1.1); }
}

