  --maroon-glow: rgba(136, 19, 55, 0.12);

  /* Popping Accents */
  --indigo-accent: #312e81; /* Deep navy/indigo */
  --mint-green: #047857; /* Rich forest green */
  --coral-orange: #c2410c; /* Deep coral */
  --sky-blue: #0369a1; /* Deep sky blue */
  --amber-gold: #b45309; /* Deep amber gold */

  /* Card Aesthetics */
  --card-bg: #ffffff;
  --card-border: rgba(136, 19, 55, 0.18); /* Elegant maroon border */
  --card-shadow: 0 10px 25px -5px rgba(136, 19, 55, 0.05), 0 8px 10px -6px rgba(136, 19, 55, 0.05);
  --card-shadow-hover: 0 20px 25px -5px rgba(136, 19, 55, 0.1), 0 10px 10px -6px rgba(136, 19, 55, 0.1);
}

/* Dark Theme Variables (Dark Maroon Black) */
.theme-dark {
  --background: #140207; /* Luxurious deep maroon black */
  --foreground: #ffd1d7; /* Soft light rose pink text */

  /* Maroon Palette */
  --maroon-deep: #ffd1d7; /* Highlight text matches lighter rose */
  --maroon-medium: #fda4af;
  --maroon-light: #4c0519;
  --maroon-glow: rgba(244, 63, 94, 0.15);

  /* Accents */
  --indigo-accent: #818cf8; /* Light indigo */
  --mint-green: #34d399; /* Bright mint green */
  --coral-orange: #f87171; /* Soft coral */
  --sky-blue: #38bdf8; /* Bright sky blue */
  --amber-gold: #fbbf24; /* Bright gold */

  /* Card Aesthetics */
  --card-bg: #1c050a; /* Deep rich wine card */
